For anybody else struggling with this. I removed the timezone info from the dates that I pass into dateutil, I'm also using to `ignoretz` parameter to help with timezone details embedded inside the calendar. This solves the datetime comparison problems.

I'm then storing the UID of the expanded events so that I can replace them with matching expanding events (i.e. when you change the third event in a recurrence you don't want to see two events).

I'm not explaining myself well, here's some updated code:

```python
def get_recurrence_lines(event):
    recurrence_lines = ['RRULE', 'EXRULE', 'RDATE', 'EXDATE']
    for rl in recurrence_lines:
        values = event.get(rl)
        if values:
            if isinstance(values, list):
                for value in values:
                    value = value.to_ical().decode('utf-8')
                    yield f'{rl}:{value}'
            else:
                value = values.to_ical().decode('utf-8')
                yield f'{rl}:{value}'

def expand_event(event):
    if 'RRULE' in event:
        event_start = event['DTSTART'].dt
        tz = getattr(event_start, 'tzinfo', None)
        event_start = event_start.replace(tzinfo=None)

        rrule = '\n'.join(get_recurrence_lines(event))
        ruleset = rrulestr(rrule, dtstart=event_start, forceset=True, ignoretz=True)

        for event_dt_start in ruleset.before(datetime.now()):
            yield event_dt_start.replace(tzinfo=tz), False
    else:
        if event['DTSTART'].dt < datetime.now():
            yield event['DTSTART'].dt, True

ical = icalendar.Calendar.from_ical(data)
events = {}
for ev in ical.walk(name='VEVENT'):
    for event, preferred in expand_event(ev):
        key = (event['UID'], event['DTSTART'])
        if key not in events or preferred:
            events[key] = event
for e in events.values():
    print(e)
```

